mapper.select:
   		 select count(t1.*)
		 from esg.tb_toolboxmeeting t1
		 where t1.write_year = #{writeYear}
		 	and t1.comp_id  = #{compId}
		 	and t1.use_yn = 'Y'
			and substring(t1.tbm_date from 5 for 2) = #{id}

   		 select count(t1.*)
		 from esg.tb_classification_hazards t1
		 where t1.write_year = #{writeYear}
		 	and t1.comp_id  = #{compId}
		 	and t1.use_yn = 'Y'

   		 select count(distinct t1.hr_id)
		 from esg.tb_workers_opinions_on_hazards_info t1
		 where t1.write_year = #{writeYear}
		 	and t1.comp_id  = #{compId}
		 	and t1.use_yn = 'Y'

   		 select count(t1.*)
		 from esg.tb_result_of_risk_assessment_training t1
		 where t1.write_year = #{writeYear}
		 	and t1.comp_id  = #{compId}
		 	and t1.use_yn = 'Y'

select t1.chart_id
from esg.tb_emergency_control_org_chart t1
where t1.write_year = #{writeYear}
	and t1.comp_id = #{compId}
	and t1.confirm_yn = 'Y'
	and t1.use_yn = 'Y'

   		 select count(t1.*)
		 from esg.tb_emergency_control_task_asgmt t1
		 where t1.write_year = #{writeYear}
		 	and t1.comp_id  = #{compId}
		 	and t1.use_yn = 'Y'

select count(t1.*)
	 from esg.tb_legal_manage t1
	 where t1.write_year = #{writeYear}
	 	and t1.comp_id  = #{compId}
	 	and t1.use_yn = 'Y'

select count(t1.*)
	 from esg.tb_legal_review t1
	 where t1.write_year = #{writeYear}
	 	and t1.comp_id  = #{compId}
	 	and t1.use_yn = 'Y'

select count(t1.*)
  from (
		select ter.write_year
		  from esg.tb_evaluation_report ter
		 where ter.write_year = #{writeYear}
		   and ter.comp_id  = #{compId}
		   and ter.use_yn = 'Y'
		   and substring(ter.evaluation_dt from 5 for 2) = #{id}
		 union all
		select tlce.write_year
		  from esg.tb_legal_comlpliance_evaluation tlce
		 where tlce.write_year = #{writeYear}
		   and tlce.comp_id  = #{compId}
		   and tlce.use_yn = 'Y'
		   and substring(tlce.legal_evaluation_dt from 5 for 2) = #{id}
		) t1

select count(t1.*)
from (
	select tab1.write_year
	from esg.tb_training_plan_implementation tab1
	where tab1.use_yn = 'Y'
		and tab1.write_year = #{writeYear}
		and tab1.comp_id = #{compId}
		and substring(tab1.training_date from 5 for 2) = #{id}
	union all
	select tab2.write_year
	from esg.tb_training_result_report tab2
	where tab2.use_yn = 'Y'
		and tab2.write_year = #{writeYear}
		and tab2.comp_id = #{compId}
		and substring(tab2.training_date from 5 for 2) = #{id}
) t1

select count(t1.*)
from esg.tb_action_objective_plan t1
where t1.write_year = #{writeYear}
	and t1.comp_id = #{compId}
	and t1.use_yn = 'Y'

select count(t1.*)
from esg.tb_action_detail_plan t1
where t1.write_year = #{writeYear}
	and t1.comp_id = #{compId}
	and t1.use_yn = 'Y'

select count(t1.*)
from esg.tb_action_detail_plan t1
where t1.write_year = #{writeYear}
	and t1.comp_id = #{compId}
	and t1.use_yn = 'Y'

		select count(t1.*)
		from esg.tb_safety_health_objectives t1
		where t1.write_year = #{writeYear}
			and t1.comp_id = #{compId}
            and t1.use_yn = 'Y'

		select count(t1.*)
		from esg.tb_safety_health_objectives t1
		where t1.write_year = #{writeYear}
			and t1.comp_id = #{compId}
            and t1.use_yn = 'Y'
